import React from 'react';
import { useAndesContext, useId } from '@andes/context';
import PropTypes from 'prop-types';
import TagCollapsed from '../TagCollapsed';
import enTranslations from '../../translations/en/messages.json';
import zhCnTranslations from '../../translations/zh-CN/messages.json';
import esArTranslations from '../../translations/es-AR/messages.json';
import ptBrTranslations from '../../translations/pt-BR/messages.json';

/** @type {typeof import('../..').TagCollapsed} */
// eslint-disable-next-line react/prop-types
const TagCollapsedContainer = ({ ref, ...props }) => {
  const componentId = useId(props.id);

  const { i18n } = useAndesContext(
    '@andes/tag',
    { en: enTranslations, 'es-AR': esArTranslations, 'pt-BR': ptBrTranslations, 'zh-CN': zhCnTranslations },
  );

  return (
    <TagCollapsed
      {...props}
      id={componentId}
      i18n={i18n}
      innerRef={ref}
    />
  );
};

TagCollapsedContainer.displayName = 'TagCollapsedContainer';

TagCollapsedContainer.propTypes = {
  id: PropTypes.string,
};

export default TagCollapsedContainer;
