import React, { useState } from 'react';
import { namespace } from '../constants';
import { Thumbnail } from '@andes/thumbnail';

/** @typedef {import('../../index').AssetConfig} PublicAssetConfig */

/**
 * @typedef {Object} PrivateAssetConfig
 * @prop {string} [imageAlt] - The alt text of the image.
 */

/**
 * @typedef {PublicAssetConfig & PrivateAssetConfig} AssetProps
 */

/**
 * Renders a Thumbnail based on the provided AssetProps.
 * It can render an icon, image, or text Thumbnail.
 *
 * @param {AssetProps} props - The properties object.
 * @return {React.ReactElement} The Thumbnail component with the appropriate content.
 */
const ThumbnailAsset = ({ icon, imageUrl, text, color, imageAlt }) => {
  const [imageError, setImageError] = useState(false);
  const onImageError = () => setImageError(true);

  const renderContent = () => {
    if (icon) return icon;
    if (text) return <span>{text}</span>;
    if (imageUrl) {
      return imageError ? <></> : (
        <img
          src={imageUrl}
          alt={imageAlt}
          onError={onImageError}
        />
      );
    }

    return <></>;
  };

  return (
    <Thumbnail
      className={`${namespace}--internal-thumbnail`}
      size="24"
      color={color}
    >
      {renderContent()}
    </Thumbnail>
  );
};

export default ThumbnailAsset;
