import {
  COLOR_POSITIVE,
  COLOR_CAUTION,
  COLOR_NEGATIVE,
  DEPRECATED_COLOR_GREEN,
  DEPRECATED_COLOR_ORANGE,
  DEPRECATED_COLOR_RED,
  // ALL_COLORS is used for types
  // eslint-disable-next-line no-unused-vars
  ALL_COLORS,
} from '../constants/colors';

/**
 * @param {typeof ALL_COLORS[number]} [color]
 * @return {COLOR_NEGATIVE| COLOR_CAUTION | COLOR_POSITIVE | undefined}
 */
// This function attempts to keep backwards compatibility with color prop
const computeColor = (color) => {
  switch (color) {
    case DEPRECATED_COLOR_RED:
    case COLOR_NEGATIVE:
      return COLOR_NEGATIVE;
    case DEPRECATED_COLOR_ORANGE:
    case COLOR_CAUTION:
      return COLOR_CAUTION;
    case DEPRECATED_COLOR_GREEN:
    case COLOR_POSITIVE:
      return COLOR_POSITIVE;
    default:
      return undefined;
  }
};

export default computeColor;
