import React, { useState, useMemo } from 'react';
import { useId } from '@andes/context';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { namespace } from '../constants';
import FeedbackPositive16 from '@andes/icons/FeedbackPositive16';
import { VisuallyHidden } from '@andes/visually-hidden';
import { computeDataAndesState } from '@andes/common/build/utils/computeDataAndesState';
import ThumbnailAsset from './ThumbnailAsset';
import { useThemeContext } from '@andes/themes';

/** @type {typeof import('../..').TagChoice} */
const TagChoice = ({
  asset,
  className,
  defaultSelected,
  id,
  label,
  onClick,
  selected,
  size = 'large',
  srLabel,
  disabled = false,
  ref,
}) => {
  const componentId = useId(id);

  const { getThemedComponentClasses, themeHash } = useThemeContext();

  // eslint-disable-next-line react-hooks/exhaustive-deps
  const isUncontrolled = useMemo(() => selected === undefined, []);

  const [uncontrolledSelected, setUncontrolledSelected] = useState(
    defaultSelected,
  );

  const isSelected = () => {
    if (isUncontrolled) return uncontrolledSelected;

    return selected;
  };

  /** @param {React.MouseEvent<HTMLButtonElement>} event */
  const handleClick = (event) => {
    if (isUncontrolled) {
      setUncontrolledSelected((state) => !state);
    }

    if (typeof onClick === 'function') onClick(event, !isSelected());
  };

  const tagClassName = classNames(namespace, `${namespace}--choice`, className, {
    [`${namespace}--clickable`]: !disabled,
    [`${namespace}--${size}`]: size,
    [`${namespace}--selected`]: isSelected(),
    [`${namespace}--disabled`]: disabled,
  },
  getThemedComponentClasses?.('tag'),
  );

  return (
    <button
      className={tagClassName}
      ref={ref}
      id={componentId}
      onClick={handleClick}
      aria-pressed={isSelected()}
      type="button"
      disabled={disabled}
      data-andes-tag
      data-andes-tag-type="choice"
      {...themeHash}
      {...computeDataAndesState({ disabled, selected: isSelected() })}
    >
      {asset && size === 'large' && (
        <ThumbnailAsset {...asset} imageAlt={label} />
      )}
      <div className={`${namespace}__label`}>
        {srLabel && <VisuallyHidden>{srLabel}</VisuallyHidden>}
        {label}
      </div>
      {(isSelected() && !disabled) && (
        <span aria-hidden className={`${namespace}__icon-container ${namespace}__icon-container-check`} data-andes-tag-check-icon>
          <FeedbackPositive16 color="currentColor" />
        </span>
      )}
    </button>
  );
};

TagChoice.displayName = 'TagChoice';

TagChoice.propTypes = {
  // asset could be null according to how prop-types handles optional params
  asset: PropTypes.shape({
    icon: PropTypes.element,
    imageUrl: PropTypes.string,
    text: PropTypes.string,
  }),
  className: PropTypes.string,
  defaultSelected: PropTypes.bool,
  id: PropTypes.string,
  label: PropTypes.string.isRequired,
  onClick: PropTypes.func,
  selected: PropTypes.bool,
  size: PropTypes.oneOf(['small', 'large']),
  srLabel: PropTypes.string,
};

export default TagChoice;
