import React from 'react';
import { namespace } from '../constants';
import classNames from 'classnames';

/**
 * @typedef {Object} TagIconProps
 * @prop {React.ReactNode} icon - The icon to render.
 */

/**
 * @param {TagIconProps} props
 * @return {React.ReactElement} The Icon for Custom Icon Tag.
 */
const TagIcon = ({ icon }) => {
  const classnames = classNames([
    `${namespace}__custom-icon`,
  ]);
  return <div className={classnames}>{ icon }</div>;
};

export default TagIcon;
