import React from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { ESCAPE } from '@andes/common/build/constants/keyboardCodes';
import { Popper } from '@andes/popper';
import { namespace as tagNamespace, namespaceCollapsed } from './constants/index';

/** @typedef {import('..').TagCollapsedProps} TagCollapsedPublicProps */

/** @typedef {React.ReactElement<import('../index').TagProps>} Tag */

/**
 * @typedef {Object} TagCollapsedInternalProps
 * @prop {React.LegacyRef<HTMLUListElement> | undefined} innerRef
 * @prop {import('@meli/i18n').I18n} i18n
 */

/** @typedef {TagCollapsedPublicProps & TagCollapsedInternalProps} TagCollapsedProps */

/** @extends React.Component<TagCollapsedProps> */
class TagCollapsed extends React.Component {
  /** @param {TagCollapsedProps} props */
  constructor(props) {
    super(props);

    this.state = {
      moreTagsVisible: false,
    };

    this.buttonRef = React.createRef();
    this.showMoreTags = this.showMoreTags.bind(this);
    this.hideMoreTags = this.hideMoreTags.bind(this);
    this.onBlur = this.onBlur.bind(this);
    this.onKeyDown = this.onKeyDown.bind(this);
  }

  /** @param {number | string} index */
  getKeyByIndex = (index) => {
    const { id } = this.props;
    return `${id}-item-${index}`;
  };

  /** @param {Tag[]} tags */
  getVisibleTags(tags) {
    const { limit = 2 } = this.props;
    return tags.slice(0, limit);
  }

  /** @param {Tag[]} tags */
  getEllipseTag(tags) {
    const { limit = 2, disabled = false, i18n } = this.props;
    const { moreTagsVisible } = this.state;
    const size = tags[0]?.props?.size || 'large';
    const label = `+${tags.length - limit}`;

    const buttonTagClassName = classNames(
      tagNamespace,
      `${tagNamespace}--${size}`,
      {
        [`${tagNamespace}--selectable`]: !disabled,
        [`${tagNamespace}--clickable`]: !disabled,
        [`${tagNamespace}--disabled`]: disabled,
      },
    );

    const popperOptions = {
      modifiers: [{
        name: 'offset',
        options: {
          offset: [0, 6],
        },
      }],
    };

    const listItemTagClassName = classNames(
      `${namespaceCollapsed}__wrap`,
      `${namespaceCollapsed}__list-item`,
    );

    return (
      // eslint-disable-next-line jsx-a11y/no-noninteractive-element-interactions
      <li className={listItemTagClassName} onKeyDown={this.onKeyDown}>
        <Popper
          interactive
          placement="bottom-start"
          trigger="click"
          visible={moreTagsVisible}
          popperOptions={popperOptions}
          onClickOutside={this.hideMoreTags}
          // Andes zIndex should be in a variable which needs to be imported
          zIndex={10000}
          content={(
            <div className={`${namespaceCollapsed}__more`} role="dialog" onBlur={this.onBlur}>
              <ul className={`${namespaceCollapsed}__list`}>
                {tags.slice(limit).map((tag, index) => (
                  <li key={this.getKeyByIndex(index)} className={`${namespaceCollapsed}__list-item`}>{tag}</li>
                ))}
              </ul>
            </div>
          )}
          focusScope
        >
          <button
            onClick={moreTagsVisible ? this.hideMoreTags : this.showMoreTags}
            aria-haspopup="dialog"
            aria-expanded={moreTagsVisible}
            aria-label={i18n.pgettext(
              tagNamespace, 'mostrar {0} mas', tags.length - limit,
            )}
            className={buttonTagClassName}
            ref={this.buttonRef}
            disabled={disabled}
            type="button"
            data-andes-tag-collapsed-ellipse
          >
            <span className={`${tagNamespace}__label`}>{label}</span>
          </button>
        </Popper>
      </li>
    );
  }

  showMoreTags() {
    const { disabled = false } = this.props;

    if (disabled) return;

    this.setState({
      moreTagsVisible: true,
    });
  }

  hideMoreTags() {
    this.setState({
      moreTagsVisible: false,
    });
  }

  /** @param {React.FocusEvent<HTMLDivElement>} event */
  focusInCurrentTarget(event) {
    const { relatedTarget, currentTarget } = event;
    if (relatedTarget === null) return false;

    let target = relatedTarget.parentNode;

    while (target !== null) {
      if (target === currentTarget) return true;
      target = target.parentNode;
    }

    return false;
  }

  /** @param {React.FocusEvent<HTMLDivElement>} event */
  onBlur(event) {
    if (!this.focusInCurrentTarget(event)) {
      this.hideMoreTags();
    }
  }

  /** @param {React.KeyboardEvent<HTMLLIElement>} event */
  onKeyDown(event) {
    const { code } = event;
    const button = this.buttonRef?.current;

    if (code === ESCAPE && button) {
      this.hideMoreTags();
      button.focus();
    }
  }

  render() {
    const {
      children,
      limit = 2,
      srLabel,
      innerRef,
    } = this.props;

    const collapsedTagClass = classNames(
      `${namespaceCollapsed}`,
      `${namespaceCollapsed}__list`,
      `${namespaceCollapsed}__list-main`,
    );

    // @ts-expect-error
    // children is restricted to be an array of Tag components
    const /** @type {Tag[]} */ tagChildren = React.Children.toArray(children);
    const exceedLimit = tagChildren.length > limit;

    return (
      <ul
        className={collapsedTagClass}
        aria-label={srLabel}
        ref={innerRef}
      >
        {this.getVisibleTags(tagChildren).map((tag, index) => (
          <li key={this.getKeyByIndex(index)} className={`${namespaceCollapsed}__list-item`}>{tag}</li>
        ))}
        { exceedLimit && this.getEllipseTag(tagChildren) }
      </ul>
    );
  }
}

TagCollapsed.displayName = 'TagCollapsed';

TagCollapsed.propTypes = {
  children: PropTypes.node.isRequired,
  disabled: PropTypes.bool,
  id: PropTypes.string.isRequired,
  limit: PropTypes.number,
  srLabel: PropTypes.string,
  i18n: PropTypes.shape({}).isRequired,
  innerRef: PropTypes.shape({
    current: PropTypes.oneOfType([PropTypes.node, PropTypes.object]),
  }),
};

export default TagCollapsed;
